qry:select.qry:xquery:
				for $r in sql('
			SELECT 
{%? ($ESTR/ESTR/@Agrupar='categ') {% l97.c_categoria_ult, org18_convenios.c_convenio, max(org18_convenios.d_convenio) as d_convenio, max(org18_categorias.d_categoria) as d_categoria,	%} {% %} %}
{%? ($ESTR/ESTR/@Agrupar='c_ubic') {% l97.c_ubicacion, max(ORG03_UBICACIONES.d_ubicacion) as d_ubicacion,	%} {% %} %}
{%? ($ESTR/ESTR/@Agrupar='centro') {% l97.c_centro_costo_ult, max(ORG08_CS_COSTO.d_centro_costo) as d_centro_costo, %} {% %} %}
{%? ($ESTR/ESTR/@Agrupar='afjp') {% l97.c_afjp, max(PER03_AFJP.d_afjp) as d_afjp, %} {% %} %}
{%? ($ESTR/ESTR/@Agrupar='sindicato') {% l97.c_sindicato, max(PER30_SINDICATOS.d_sindicato) as d_sindicato, %} {% %} %}
{%? ($ESTR/ESTR/@Agrupar='obra') {%	l97.c_obra_social, max(PER06_OBRAS_SOC.d_obra_social) as d_obra_social, %} {% %} %}

l97.{%= $ESTR/ESTR/@gru %} as gru, 

{%? ($ESTR/ESTR/@oi_liquidacion!='') {% l19.c_liquidacion, 	l19.d_titulo, %} {% %} %}		

l93.c_empresa, l93.d_empresa, 
l99.e_periodo, o03.oi_empresa
FROM 
LIQ93_EMPRESAS as l93, 
LIQ99_LIQUIDACION as l99,
LIQ19_LIQUIDACION as l19,
LIQ19_EJECUCIONES as e19,
org03_empresas as o03, 
LIQ97_PERSONAL_EMP as l97,
LIQ99_RECIBOS as r99,
LIQ20_TOT_LIQ_PER as r20
{%? ($ESTR/ESTR/@Agrupar='centro') {% , ORG08_CS_COSTO %} {% %} %}
{%? ($ESTR/ESTR/@Agrupar='c_ubic') {% , ORG03_UBICACIONES %} {% %} %}
{%? ($ESTR/ESTR/@Agrupar='afjp') {% , PER03_AFJP %}	{% %} %}
{%? ($ESTR/ESTR/@Agrupar='sindicato') {% , PER30_SINDICATOS %}	{% %} %}
{%? ($ESTR/ESTR/@Agrupar='obra') {% , PER06_OBRAS_SOC %} {% %} %}
{%? ($ESTR/ESTR/@Agrupar='categ') {% , org18_categorias, org18_convenios %} {% %} %}
JOIN
{%? ($ESTR/ESTR/@Agrupar='categ') {%  org18_categorias.c_categoria INNER l97.c_categoria_ult , org18_convenios.c_convenio INNER l97.c_convenio , org18_categorias.oi_convenio INNER org18_convenios.oi_convenio ,		%} {% %} %}                                                
{%? ($ESTR/ESTR/@Agrupar='centro') {%  l97.c_centro_costo_ult INNER ORG08_CS_COSTO.c_centro_costo , %} {% %} %}
{%? ($ESTR/ESTR/@Agrupar='c_ubic') {%  l97.c_ubicacion INNER ORG03_UBICACIONES.c_ubicacion , o03.oi_empresa INNER ORG03_UBICACIONES.oi_empresa, %} {% %} %}
{%? ($ESTR/ESTR/@Agrupar='afjp') {% l97.c_afjp INNER PER03_AFJP.c_afjp , 	%} {% %} %}
{%? ($ESTR/ESTR/@Agrupar='sindicato') {% l97.c_sindicato INNER PER30_SINDICATOS.c_sindicato , %} {% %} %}
{%? ($ESTR/ESTR/@Agrupar='obra') {% l97.c_obra_social INNER PER06_OBRAS_SOC.c_obra_social , %} {% %} %}		
l99.oi_liquidacion_ddo INNER r99.oi_liquidacion_ddo,
r99.oi_tot_liq_per INNER r20.oi_tot_liq_per,
r20.oi_per_emp_ddo INNER l97.oi_per_emp_ddo,
l93.oi_empresa_ddo INNER l99.oi_empresa_ddo,
e19.oi_liquidacion_ddo INNER l99.oi_liquidacion_ddo,
l19.oi_liquidacion INNER e19.oi_liquidacion,
l93.c_empresa INNER o03.c_empresa
WHERE
o03.oi_empresa = {#SOURCE:@oi_empresa}
and l99.e_periodo =  {#SOURCE:@e_periodo}
{%? ($ESTR/ESTR/@oi_liquidacion!='') {% and l19.oi_liquidacion = {$ESTR/ESTR/@oi_liquidacion} %} {% %} %}
and l99.c_estado = \'F\'
{%? (#SOURCE:@l_simulacion!='')	{% AND l19.l_simulacion = {%= #SOURCE:@l_simulacion %} %} {% %} %} 
{%? (#PARAMIN:@cb_confidenciales != '' and #PARAMIN:@cb_confidenciales!='T' ) 
{%  
{%? (#PARAMIN:@cb_confidenciales = 'C') {%	AND r20.l_confidencial = 1%}{% AND r20.l_confidencial = 0 %} %} 
%} 
{%	%}
%}
group by
l93.c_empresa, 
l93.d_empresa,
o03.oi_empresa, 
l99.e_periodo,
l97.{%= $ESTR/ESTR/@gru %}
{%? ($ESTR/ESTR/@Agrupar='categ') {% ,org18_convenios.c_convenio %} {% %} %}
{%? ($ESTR/ESTR/@oi_liquidacion!='') {% ,l19.c_liquidacion, l19.d_titulo %} {% %} %}			
order by gru asc
')/ROWS/ROW

				for $r in sql('
SELECT
	sum(P.{%=$COL/@c_sumar%}) as suma,
	L97.e_numero_legajo,
	L97.{%= $ESTR/ESTR/@gru %} AS gru,
	(NUMBER2STRING(L97.e_numero_legajo) || \'_\' || L97.{%= $ESTR/ESTR/@gru %}) AS leg_gru
FROM
LIQ97_PERSONAL_EMP AS L97, LIQ20_TOT_LIQ_PER as L20, 
LIQ20_CONC_LIQ_PER as P, LIQ96_CONCEPTOS as C,
LIQ14_CONCEPTOS as R, LIQ99_RECIBOS as T,
LIQ99_LIQUIDACION as L99,
LIQ93_EMPRESAS as L93,
ORG03_EMPRESAS as O03 
JOIN
L20.oi_tot_liq_per INNER T.oi_tot_liq_per,
L20.oi_per_emp_ddo INNER L97.oi_per_emp_ddo,
P.oi_tot_liq_per INNER L20.oi_tot_liq_per,
P.oi_concepto_ddo INNER C.oi_concepto_ddo,
C.c_concepto INNER R.c_concepto,
L99.oi_liquidacion_ddo INNER T.oi_liquidacion_ddo,
L93.oi_empresa_ddo INNER L99.oi_empresa_ddo,
L93.c_empresa INNER O03.c_empresa
WHERE 
L99.e_periodo = {#TEMP:@e_periodo}
AND O03.oi_empresa =  {#TEMP:@oi_empresa}
{%? (string($SOURCE/CON/@oi_concepto)!='') {% and R.oi_concepto in ({%= $SOURCE/CON/@oi_concepto %}) %} {% and 1 = 2 %} %}
{%? (#TEMP:@c_centro_costo_ult!='') {% AND L97.c_centro_costo_ult = \'{%=#TEMP:@c_centro_costo_ult%}\' %} {% %} %}
{%? (#TEMP:@c_ubicacion!='') {% AND L97.c_ubicacion = \'{%=#TEMP:@c_ubicacion%}\' %} {% %} %}
{%? (#TEMP:@c_sindicato!='') {% AND L97.c_sindicato = \'{%=#TEMP:@c_sindicato%}\' %} {% %} %}
{%? (#TEMP:@c_obra_social!='') {% AND L97.c_obra_social = \'{%=#TEMP:@c_obra_social%}\' %} {% %} %}
{%? (#TEMP:@c_afjp!='') {% AND L97.c_afjp = \'{%=#TEMP:@c_afjp%}\' %} {% %} %}
{%? (#TEMP:@c_categoria!='') {% AND L97.c_categoria_ult = \'{%=#TEMP:@c_categoria%}\' and L97.c_convenio = \'{%=#TEMP:@c_convenio%}\' %} {% %} %}
group by L97.e_numero_legajo, L97.{%= $ESTR/ESTR/@gru %}
UNION
SELECT 0 as suma, L197.e_numero_legajo, L197.{%= $ESTR/ESTR/@gru %} AS gru,
(NUMBER2STRING(L197.e_numero_legajo) || \'_\' || L197.{%= $ESTR/ESTR/@gru %}) AS leg_gru
FROM
LIQ97_PERSONAL_EMP AS L197, LIQ20_TOT_LIQ_PER as L120, LIQ99_RECIBOS as T1, LIQ99_LIQUIDACION as L1_99, LIQ93_EMPRESAS as L1_93,ORG03_EMPRESAS as O1_03 
JOIN
L120.oi_tot_liq_per INNER T1.oi_tot_liq_per,
L120.oi_per_emp_ddo INNER L197.oi_per_emp_ddo,
L1_99.oi_liquidacion_ddo INNER T1.oi_liquidacion_ddo,
L1_93.oi_empresa_ddo INNER L1_99.oi_empresa_ddo,
L1_93.c_empresa INNER O1_03.c_empresa
WHERE
L1_99.e_periodo = {#TEMP:@e_periodo}
AND O1_03.oi_empresa =  {#TEMP:@oi_empresa}
{%? (#TEMP:@c_centro_costo_ult!='') {% and L197.c_centro_costo_ult = \'{%=#TEMP:@c_centro_costo_ult%}\' %} {% %} %}
{%? (#TEMP:@c_ubicacion!='') {% and L197.c_ubicacion = \'{%=#TEMP:@c_ubicacion%}\' %} {% %} %}
{%? (#TEMP:@c_sindicato!='') {% and L197.c_sindicato = \'{%=#TEMP:@c_sindicato%}\' %} {% %} %}
{%? (#TEMP:@c_obra_social!='') {% and L197.c_obra_social = \'{%=#TEMP:@c_obra_social%}\' %} {% %} %}
{%? (#TEMP:@c_afjp!='') {% and L197.c_afjp = \'{%=#TEMP:@c_afjp%}\' %} {% %} %}
{%? (#TEMP:@c_categoria!='') {% and L197.c_categoria_ult = \'{%=#TEMP:@c_categoria%}\' and L197.c_convenio = \'{%=#TEMP:@c_convenio%}\' %} {% %} %}
and L197.e_numero_legajo not in (SELECT  
L297.e_numero_legajo 
FROM LIQ97_PERSONAL_EMP AS L297, LIQ20_TOT_LIQ_PER as L220, 
LIQ20_CONC_LIQ_PER as P1, LIQ96_CONCEPTOS as C1, LIQ14_CONCEPTOS as R1, LIQ99_RECIBOS as T2, LIQ99_LIQUIDACION as L2_99, LIQ93_EMPRESAS as L2_93,ORG03_EMPRESAS as O2_03
JOIN
L220.oi_tot_liq_per INNER T2.oi_tot_liq_per,
L220.oi_per_emp_ddo INNER L297.oi_per_emp_ddo,
P1.oi_tot_liq_per INNER L220.oi_tot_liq_per,
P1.oi_concepto_ddo INNER C1.oi_concepto_ddo,
C1.c_concepto INNER R1.c_concepto,
L2_99.oi_liquidacion_ddo INNER T2.oi_liquidacion_ddo,
L2_93.oi_empresa_ddo INNER L2_99.oi_empresa_ddo,
L2_93.c_empresa INNER O2_03.c_empresa
WHERE
L2_99.e_periodo = {%= #TEMP:@e_periodo %}
AND O2_03.oi_empresa = {%= #TEMP:@oi_empresa %}
{%? (string($SOURCE/CON/@oi_concepto)!='') {% and R1.oi_concepto in ({%= $SOURCE/CON/@oi_concepto %}) %} {% and 1 = 2  %} %}
{%? (#TEMP:@c_centro_costo_ult!='') {% and L297.c_centro_costo_ult = \'{%=#TEMP:@c_centro_costo_ult%}\' %} {% %} %}
{%? (#TEMP:@c_ubicacion!='') {% and L297.c_ubicacion = \'{%=#TEMP:@c_ubicacion%}\' %} {% %} %}
{%? (#TEMP:@c_sindicato!='') {% and L297.c_sindicato = \'{%=#TEMP:@c_sindicato%}\' %} {% %} %}
{%? (#TEMP:@c_obra_social!='') {% and L297.c_obra_social = \'{%=#TEMP:@c_obra_social%}\' %} {% %} %}
{%? (#TEMP:@c_afjp!='') {% and L297.c_afjp = \'{%=#TEMP:@c_afjp%}\' %} {% %} %}
{%? (#TEMP:@c_categoria!='') {% and L297.c_categoria_ult =  \'{%=#TEMP:@c_categoria%}\' and L297.c_convenio = \'{%=#TEMP:@c_convenio%}\' %} {% %} %})
group by L197.e_numero_legajo, L197.{%= $ESTR/ESTR/@gru %}
order by e_numero_legajo ASC')/ROWS/ROW,
$x in $TEMP/GROUP/PER
join $r/@leg_gru inner $x/@leg_gru
